#define BLOCK_SIZE 16

__kernel void lud_diagonal(__global float* a, __local float* local_a, int size, int offset) {
    int i, j, k;
    int local_idx = get_local_id(0);

    if (local_idx >= BLOCK_SIZE) return;

    for (i = 0; i < BLOCK_SIZE; i++) {
        if (i == local_idx) {
            for (j = i; j < BLOCK_SIZE; j++) {
                float sum = 0.0f;
                for (k = 0; k < i; k++) {
                    sum += a[(offset + i) * size + (offset + k)] * a[(offset + k) * size + (offset + j)];
                }
                a[(offset + i) * size + (offset + j)] -= sum;
            }

            float diag = a[(offset + i) * size + (offset + i)];
            float inv_diag = 1.0f / diag;

            for (j = i + 1; j < BLOCK_SIZE; j++) {
                float sum = 0.0f;
                for (k = 0; k < i; k++) {
                    sum += a[(offset + j) * size + (offset + k)] * a[(offset + k) * size + (offset + i)];
                }
                a[(offset + j) * size + (offset + i)] = (a[(offset + j) * size + (offset + i)] - sum) * inv_diag;
            }
        }
    }
}

__kernel void lud_perimeter(__global float* a, __local float* temp_top, __local float* temp_left, __local float* temp_div, int size, int offset) {
    int idx = get_local_id(0);
    int total_chunks = (size - offset - BLOCK_SIZE) / BLOCK_SIZE;

    if (idx >= 2 * total_chunks) return;

    int chunk_idx;
    int is_left;

    if (idx < total_chunks) {
        chunk_idx = idx;
        is_left = 0; 
    } else {
        chunk_idx = idx - total_chunks;
        is_left = 1;
    }

    int i, j, k;
    int i_global, j_global;
    float sum;

    if (is_left == 0) {
        j_global = offset + BLOCK_SIZE * (chunk_idx + 1);
        i_global = offset;

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                temp_top[i * BLOCK_SIZE + j] = a[(i + offset) * size + (offset + j)];
            }
        }

        for (j = 0; j < BLOCK_SIZE; j++) {
            for (i = 0; i < BLOCK_SIZE; i++) {
                sum = 0.0f;
                for (k = 0; k < i; k++) {
                    sum += temp_top[i * BLOCK_SIZE + k] * a[(i_global + k) * size + (j_global + j)];
                }
                a[(i_global + i) * size + (j_global + j)] -= sum;
            }
        }
    } else {
        i_global = offset + BLOCK_SIZE * (chunk_idx + 1);
        j_global = offset;

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                temp_left[i * BLOCK_SIZE + j] = a[(i_global + i) * size + (offset + j)];
            }
        }

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                sum = 0.0f;
                for (k = 0; k < j; k++) {
                    sum += a[(i_global + i) * size + (j_global + k)] * temp_left[k * BLOCK_SIZE + j];
                }
                float divisor = a[(offset + j) * size + (offset + j)];
                a[(i_global + i) * size + (j_global + j)] = (a[(i_global + i) * size + (j_global + j)] - sum) / divisor;
            }
        }
    }
}

__kernel void lud_internal(__global float* a, __local float* temp_top, __local float* temp_left, int size, int offset) {
    int idx_x = get_local_id(0);
    int idx_y = get_local_id(1);

    int chunks_in_row = (size - offset - BLOCK_SIZE) / BLOCK_SIZE;

    if (idx_x >= chunks_in_row || idx_y >= chunks_in_row) return;

    int i_global = offset + BLOCK_SIZE * (1 + idx_y);
    int j_global = offset + BLOCK_SIZE * (1 + idx_x);

    int i, j, k;
    float sum[BLOCK_SIZE];

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            temp_top[i * BLOCK_SIZE + j] = a[(i + offset) * size + (j_global + j)];
            temp_left[i * BLOCK_SIZE + j] = a[(i_global + i) * size + (offset + j)];
        }
    }

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            sum[j] = 0.0f;
        }

        for (k = 0; k < BLOCK_SIZE; k++) {
            float l_val = temp_left[i * BLOCK_SIZE + k];
            for (j = 0; j < BLOCK_SIZE; j++) {
                sum[j] += l_val * temp_top[k * BLOCK_SIZE + j];
            }
        }

        for (j = 0; j < BLOCK_SIZE; j++) {
            a[(i_global + i) * size + (j_global + j)] -= sum[j];
        }
    }
}
